 28→@Injectable()
 29→export class StyleModel {
 30→	private readonly logger = new Logger(StyleModel.name);
 31→	private readonly tableName = TABLE_NAME_STYLES;
 32→
 33→	constructor(
 34→		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
 35→		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
 36→		private readonly styleColorModel: StyleColorModel,
 37→		private readonly defaultUnitPriceModel: DefaultUnitPriceModel,
 38→		private readonly stylesMvModel: StylesMvModel,
 39→	) {}
 40→
 41→	async findByStyleId({
 42→		styleId,
 43→	}: {
 44→		styleId: IStyleBase['style_id'];
 45→	}): Promise<IStyleBase | null> {
 46→		try {
 47→			const result = await this.knexRead<BaseStyleDto>(this.tableName)
 48→				.where({ style_id: styleId })
 49→				.whereNull('deleted_at')
 50→				.first()
 51→				.then((result) => {
 52→					if (!result) {
 53→						return null;
 54→					}
 55→
 56→					return {
 57→						// eslint-disable-next-line
 58→						...result,
 59→						categories_ids:
 60→							typeof result.categories_ids === 'string'
 61→								? (JSON.parse(result.categories_ids) as number[])
 62→								: result.categories_ids,
 63→						categories_with_parents_ids:
 64→							typeof result.categories_with_parents_ids === 'string'
 65→								? (JSON.parse(result.categories_with_parents_ids) as number[])
 66→								: result.categories_with_parents_ids,
 67→					};
 68→				});
 69→
 70→			if (!result) {
 71→				this.logger.warn(`No style found for styleId ${styleId}`);
 72→				return null;
 73→			}
 74→
 75→			this.logger.debug(`Found style for styleId ${styleId}`);
 76→
 77→			const parsedData = this.parseStyleData(result as unknown as IStyleBase);
 78→			const dto = plainToInstance(BaseStyleDto, parsedData);
 79→			const errors = await validate(dto);
 80→			if (errors.length > 0) {
 81→				this.logger.error(
 82→					`Validation failed for style data: ${this.formatValidationErrors(errors)}`,
 83→				);
 84→				throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
 85→			}
 86→
 87→			return parsedData;
 88→		} catch (error) {
 89→			this.logger.error(
 90→				`Failed to find style for styleId ${styleId}: ${(error as Error).message}`,
 91→			);
 92→			throw error;
 93→		}
 94→	}
 95→
 96→	async findMostPopularByCategories({
 97→		categoryIds,
 98→		limit = 5,
 99→		excludeIds,
100→	}: {
101→		categoryIds: number[];
102→		limit?: number;
103→		excludeIds?: number[];
104→	}): Promise<IStyleBase[]> {
105→		try {
106→			const allResults: IStyleBase[] = [];
107→
108→			for (const categoryId of categoryIds) {
109→				let query = this.knexRead<BaseStyleDto>(this.tableName)
110→					.where('primary_category_id', categoryId)
111→					.whereNull('deleted_at');
112→
113→				if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
114→					query = query
115→						.whereNotNull('primary_category_id')
116→						.whereNotIn(
117→							'primary_category_id',
118→							FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
119→						);
120→				}
121→
122→				if (excludeIds?.length) {
123→					query = query.whereNotIn('style_id', excludeIds);
124→				}
125→
126→				const styles = await query.orderBy('purchases_count', 'desc').limit(limit);
127→
128→				const results = styles.map((style) => ({
129→					// eslint-disable-next-line
130→					...style,
131→					categories_ids:
132→						typeof style.categories_ids === 'string'
133→							? (JSON.parse(style.categories_ids) as number[])
134→							: style.categories_ids,
135→					categories_with_parents_ids:
136→						typeof style.categories_with_parents_ids === 'string'
137→							? (JSON.parse(style.categories_with_parents_ids) as number[])
138→							: style.categories_with_parents_ids,
139→				}));
140→
141→				const mappedResults = await Promise.all(
142→					results.map(async (result) => {
143→						const parsedData = this.parseStyleData(result as unknown as IStyleBase);
144→						const dto = plainToInstance(BaseStyleDto, parsedData);
145→						const errors = await validate(dto);
146→						if (errors.length > 0) {
147→							this.logger.error(
148→								`Validation failed for style data: ${this.formatValidationErrors(errors)}`,
149→							);
150→							throw new Error(
151→								`Validation failed: ${this.formatValidationErrors(errors)}`,
152→							);
153→						}
154→						return parsedData;
155→					}),
156→				);
157→				allResults.push(...mappedResults);
158→			}
159→
160→			this.logger.debug(
161→				`Found ${allResults.length} popular styles for categories ${categoryIds.join(', ')}`,
162→			);
163→			return allResults;
164→		} catch (error) {
165→			this.logger.error(
166→				`Failed to find popular styles for categories ${categoryIds.join(', ')}: ${(error as Error).message}`,
167→			);
168→			throw error;
169→		}
170→	}
171→
172→	async findMostPopularByRootCategories({
173→		categoryIds,
174→		limit = 5,
175→		excludeIds,
176→	}: {
177→		categoryIds: number[];
178→		limit?: number;
179→		excludeIds?: number[];
180→	}): Promise<{ root_category_id: number; style_id: number; purchases_count: number }[]> {
181→		try {
182→			const allResults: {
183→				root_category_id: number;
184→				style_id: number;
185→				purchases_count: number;
186→			}[] = [];
187→
188→			for (const categoryId of categoryIds) {
189→				let query = this.knexRead<BaseStyleDto>(this.tableName)
190→					.select('root_category_id', 'style_id', 'purchases_count')
191→					.where('root_category_id', categoryId)
192→					.whereNull('deleted_at');
193→
194→				if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
195→					query = query
196→						.whereNotNull('primary_category_id')
197→						.whereNotIn(
198→							'primary_category_id',
199→							FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
200→						);
201→				}
202→
203→				if (excludeIds?.length) {
204→					query = query.whereNotIn('style_id', excludeIds);
205→				}
206→
207→				const results = await query.orderBy('purchases_count', 'desc').limit(limit);
208→
209→				allResults.push(
210→					...(results as {
211→						root_category_id: number;
212→						style_id: number;
213→						purchases_count: number;
214→					}[]),
215→				);
216→			}
217→
218→			this.logger.debug(
219→				`Found ${allResults.length} popular styles for root categories ${categoryIds.join(', ')}`,
220→			);
221→			return allResults;
222→		} catch (error) {
223→			this.logger.error(
224→				`Failed to find popular styles for root categories ${categoryIds.join(', ')}: ${(error as Error).message}`,
225→			);
226→			throw error;
227→		}
228→	}
229→
230→	async findMostPopularCategories({ limit = 4 }: { limit?: number }): Promise<number[]> {
231→		try {
232→			let query = this.knexRead<BaseStyleDto>(this.tableName)
233→				.select('primary_category_id')
234→				.whereNull('deleted_at')
235→				.whereNotNull('primary_category_id');
236→
237→			if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
238→				query = query.whereNotIn(
239→					'primary_category_id',
240→					FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
241→				);
242→			}
243→
244→			const results = await query
245→				.groupBy('primary_category_id')
246→				.orderByRaw('COUNT(*) desc')
247→				.limit(limit);
248→
249→			const categoryIds = results
250→				.map((result) => result.primary_category_id)
251→				.filter((id): id is number => id !== null);
252→			this.logger.debug(`Found ${categoryIds.length} most popular categories`);
253→			return categoryIds;
254→		} catch (error) {
255→			this.logger.error(
256→				`Failed to find most popular categories: ${(error as Error).message}`,
257→			);
258→			throw error;
259→		}
260→	}
261→
262→	async findMostPopularRootCategories({
263→		limit = 4,
264→	}: {
265→		limit?: number;
266→	}): Promise<number[]> {
267→		try {
268→			let query = this.knexRead<BaseStyleDto>(this.tableName)
269→				.select('root_category_id')
270→				.whereNull('deleted_at')
271→				.whereNotNull('root_category_id');
272→
273→			if (FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS.length > 0) {
274→				query = query
275→					.whereNotNull('primary_category_id')
276→					.whereNotIn(
277→						'primary_category_id',
278→						FREQUENTLY_BOUGHT_TOGETHER_EXCLUDED_PRIMARY_CATEGORY_IDS,
279→					);
280→			}
281→
282→			const results = await query
283→				.groupBy('root_category_id')
284→				.orderByRaw('COUNT(*) desc')
285→				.limit(limit);
286→
287→			const categoryIds = results.map((result) => result.root_category_id);
288→			this.logger.debug(`Found ${categoryIds.length} most popular root categories`);
289→			return categoryIds as number[];
290→		} catch (error) {
291→			this.logger.error(
292→				`Failed to find most popular root categories: ${(error as Error).message}`,
293→			);
294→			throw error;
295→		}
296→	}
