298→	async findByStyleIds({
299→		styleIds,
300→	}: {
301→		styleIds: IStyleBase['style_id'][];
302→	}): Promise<IStyleBase[]> {
303→		try {
304→			if (styleIds.length === 0) {
305→				return [];
306→			}
307→
308→			const results = await this.knexRead<BaseStyleDto>(this.tableName)
309→				.whereIn('style_id', styleIds)
310→				.whereNull('deleted_at');
311→
312→			const mappedResults = await Promise.all(
313→				results.map(async (result) => {
