339→	async getStylesInStockByIds({
340→		styleIds,
341→	}: {
342→		styleIds: IStyleBase['style_id'][];
343→	}): Promise<IStyleBase[]> {
344→		const dto = plainToInstance(FindByStyleIdsDto, { style_ids: styleIds });
345→		const errors = await validate(dto);
346→
347→		if (errors.length > 0) {
348→			this.logger.error(
349→				`Validation failed for style IDs: ${this.formatValidationErrors(errors)}`,
350→			);
351→			throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
352→		}
353→
354→		try {
355→			const results = await this.knexRead<BaseStyleDto>(this.tableName)
356→				.whereIn('style_id', styleIds)
357→				.andWhere('is_active', true)
358→				.whereNull('deleted_at');
359→
360→			const mappedResults = await Promise.all(
361→				results.map(async (result) => {
362→					const parsedData = this.parseStyleData(result);
363→					const dto = plainToInstance(BaseStyleDto, parsedData);
364→					const errors = await validate(dto);
365→					if (errors.length > 0) {
366→						this.logger.error(
367→							`Validation failed for style data: ${this.formatValidationErrors(errors)}`,
368→						);
369→						throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
370→					}
371→					return parsedData;
372→				}),
373→			);
374→
375→			this.logger.debug(
376→				`Found ${mappedResults.length} styles out of ${styleIds.length} requested`,
377→			);
378→			return mappedResults;
379→		} catch (error) {
380→			this.logger.error(
381→				`Failed to find styles for styleIds ${styleIds.join(', ')}: ${(error as Error).message}`,
382→			);
383→			throw error;
384→		}
385→	}
