387→	async upsertStyle({
388→		data,
389→	}: {
390→		data: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
391→	}): Promise<IStyleBase> {
392→		try {
393→			const dto = plainToInstance(BaseStyleDto, data);
394→			const errors = await validate(dto, { skipMissingProperties: true });
395→
396→			if (errors.length > 0) {
397→				this.logger.error(
398→					`Validation failed for style data: ${this.formatValidationErrors(errors)}`,
399→				);
400→				throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
401→			}
402→
403→			const upsertedStyle: IStyleBase = await this.knexWrite.transaction(async (trx) => {
404→				const existing = await trx<IStyleBase>(this.tableName)
405→					.where({ style_id: data.style_id })
406→					.whereNull('deleted_at')
407→					.first();
408→
409→				if (existing) {
410→					const updateData: Record<string, unknown> = {
411→						updated_at: trx.fn.now(),
412→					};
413→
414→					Object.keys(data).forEach((key) => {
415→						if (key !== 'style_id') {
416→							if (
417→								key === 'categories_ids' ||
418→								key === 'categories_with_parents_ids' ||
419→								key === 'broad_category_names' ||
420→								key === 'sub_category_names' ||
421→								key === 'brand' ||
422→								key === 'sizes'
423→							) {
424→								updateData[key] = JSON.stringify(data[key as keyof typeof data] ?? []);
425→							} else {
426→								updateData[key] = data[key as keyof typeof data];
427→							}
428→						}
429→					});
430→
431→					await trx(this.tableName)
432→						.where({ style_id: data.style_id })
433→						.whereNull('deleted_at')
434→						.update(updateData);
435→				} else {
436→					const _id = randomUUID();
437→					const insertData: Record<string, unknown> = {
438→						_id,
439→						...data,
440→						style_id: data.style_id,
441→						primary_category_id: data.primary_category_id ?? null,
442→						root_category_id: data.root_category_id ?? null,
443→						purchases_count: data.purchases_count ?? 0,
444→						is_active: data.is_active ?? true,
445→						categories_ids: JSON.stringify(data.categories_ids ?? []),
446→						categories_with_parents_ids: JSON.stringify(
447→							data.categories_with_parents_ids ?? [],
448→						),
449→						broad_category_names: JSON.stringify(data.broad_category_names ?? []),
450→						sub_category_names: JSON.stringify(data.sub_category_names ?? []),
451→						brand: JSON.stringify(data.brand ?? []),
452→						sizes: JSON.stringify(data.sizes ?? []),
453→						created_at: trx.fn.now(),
454→						updated_at: trx.fn.now(),
455→					};
456→
457→					await trx(this.tableName).insert(insertData);
458→				}
459→
460→				const result = await trx<IStyleBase>(this.tableName)
461→					.where({ style_id: data.style_id })
462→					.whereNull('deleted_at')
463→					.first();
464→
465→				if (!result) {
466→					throw new Error(`Failed to upsert style with style ID ${data.style_id}`);
467→				}
468→
469→				return result;
470→			});
471→
472→			this.logger.debug(`Upserted style with style ID ${data.style_id}`);
473→			const plainData = instanceToPlain<BaseStyleDto>(upsertedStyle) as IStyleBase;
474→
475→			try {
476→				await this.stylesMvModel.refreshForStyle({ styleId: data.style_id });
477→			} catch (mvError: unknown) {
478→				const err = mvError instanceof Error ? mvError : new Error(String(mvError));
479→				this.logger.warn(
480→					`Failed to refresh MV for style ${data.style_id}: ${err.message}. Style data was saved successfully.`,
481→				);
482→				rollbar.error(err, { styleId: data.style_id, context: 'upsertStyle MV refresh' });
483→			}
484→
485→			return this.parseStyleData(plainData);
486→		} catch (error: unknown) {
487→			const err = error instanceof Error ? error : new Error(String(error));
488→			this.logger.error(
489→				`Failed to upsert style with style ID ${data.style_id}: ${err.message}`,
490→			);
491→			throw err;
492→		}
493→	}
494→
495→	private parseStyleData(styleData: IStyleBase): IStyleBase {
496→		return {
497→			...styleData,
498→			categories_ids:
499→				typeof styleData.categories_ids === 'string'
500→					? (JSON.parse(styleData.categories_ids) as number[] | null)
501→					: styleData.categories_ids,
502→			categories_with_parents_ids:
503→				typeof styleData.categories_with_parents_ids === 'string'
504→					? (JSON.parse(styleData.categories_with_parents_ids) as number[] | null)
505→					: styleData.categories_with_parents_ids,
506→			is_active: Boolean(styleData.is_active),
507→		};
508→	}
509→
510→	async upsertStyleWithTransaction({
511→		trx,
512→		data,
513→	}: {
514→		trx: Knex.Transaction;
515→		data: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
516→	}): Promise<IStyleBase> {
517→		try {
518→			const dto = plainToInstance(BaseStyleDto, data);
519→			const errors = await validate(dto, { skipMissingProperties: true });
520→
521→			if (errors.length > 0) {
522→				this.logger.error(
523→					`Validation failed for style data: ${this.formatValidationErrors(errors)}`,
524→				);
525→				throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
526→			}
527→
528→			const existing = await trx<IStyleBase>(this.tableName)
529→				.where({ style_id: data.style_id })
530→				.whereNull('deleted_at')
531→				.first();
532→
533→			if (existing) {
534→				const updateData: Record<string, unknown> = {
535→					updated_at: trx.fn.now(),
536→				};
537→
538→				Object.keys(data).forEach((key) => {
539→					if (key !== 'style_id') {
540→						if (
541→							key === 'categories_ids' ||
542→							key === 'categories_with_parents_ids' ||
543→							key === 'broad_category_names' ||
544→							key === 'sub_category_names' ||
545→							key === 'brand' ||
546→							key === 'sizes'
547→						) {
548→							updateData[key] = JSON.stringify(data[key as keyof typeof data] ?? []);
549→						} else {
550→							updateData[key] = data[key as keyof typeof data];
551→						}
552→					}
553→				});
554→
555→				await trx(this.tableName)
556→					.where({ style_id: data.style_id })
557→					.whereNull('deleted_at')
558→					.update(updateData);
559→			} else {
560→				const _id = randomUUID();
561→				const insertData: Record<string, unknown> = {
562→					_id,
563→					...data,
564→					categories_ids: JSON.stringify(data.categories_ids ?? []),
565→					categories_with_parents_ids: JSON.stringify(
566→						data.categories_with_parents_ids ?? [],
567→					),
568→					broad_category_names: JSON.stringify(data.broad_category_names ?? []),
569→					sub_category_names: JSON.stringify(data.sub_category_names ?? []),
570→					brand: JSON.stringify(data.brand ?? []),
571→					sizes: JSON.stringify(data.sizes ?? []),
572→					created_at: trx.fn.now(),
573→					updated_at: trx.fn.now(),
574→				};
575→
576→				await trx(this.tableName).insert(insertData);
577→			}
578→
579→			const result = await trx<IStyleBase>(this.tableName)
580→				.where({ style_id: data.style_id })
581→				.whereNull('deleted_at')
582→				.first();
583→
584→			if (!result) {
585→				throw new Error(`Failed to upsert style with style ID ${data.style_id}`);
586→			}
587→
588→			this.logger.debug(`Upserted style with style ID ${data.style_id}`);
589→			const plainData = instanceToPlain<BaseStyleDto>(result) as IStyleBase;
590→			return this.parseStyleData(plainData);
591→		} catch (error: unknown) {
592→			const err = error instanceof Error ? error : new Error(String(error));
593→			this.logger.error(
594→				`Failed to upsert style with style ID ${data.style_id}: ${err.message}`,
595→			);
596→			throw err;
597→		}
598→	}
599→
600→	async saveCompleteStyle({
601→		styleData,
602→		colors,
603→		defaultUnitPrices,
604→	}: {
605→		styleData: Partial<IStyleCreate> & { style_id: IStyleBase['style_id'] };
606→		colors: Omit<IStyleColorCreate, 'style_id'>[];
607→		defaultUnitPrices: Omit<IDefaultUnitPriceCreate, 'style_id'>[];
608→	}): Promise<void> {
609→		try {
610→			await this.knexWrite.transaction(async (trx) => {
611→				await this.upsertStyleWithTransaction({ trx, data: styleData });
612→
613→				for (const color of colors) {
614→					await this.styleColorModel.upsertStyleWithTransaction({
615→						trx,
616→						data: {
617→							style_id: styleData.style_id,
618→							...color,
619→						},
620→					});
621→				}
622→
623→				for (const priceData of defaultUnitPrices) {
624→					await this.defaultUnitPriceModel.upsertWithTransaction({
625→						trx,
626→						data: {
627→							style_id: styleData.style_id,
628→							...priceData,
629→						},
630→					});
631→				}
632→			});
633→
634→			this.logger.debug(
635→				`Successfully saved complete style with ${colors.length} colors and ${defaultUnitPrices.length} prices for style ${styleData.style_id}`,
636→			);
637→		} catch (error: unknown) {
638→			const err = error instanceof Error ? error : new Error(String(error));
639→			this.logger.error(
640→				`Failed to save complete style ${styleData.style_id}: ${err.message}`,
641→			);
642→			throw err;
643→		}
644→
645→		try {
646→			await this.stylesMvModel.refreshForStyle({ styleId: styleData.style_id });
647→		} catch (error: unknown) {
648→			const err = error instanceof Error ? error : new Error(String(error));
649→			this.logger.warn(
650→				`Failed to refresh MV for style ${styleData.style_id}: ${err.message}. Style data was saved successfully.`,
651→			);
652→			rollbar.error(err, {
653→				styleId: styleData.style_id,
654→				context: 'saveCompleteStyle MV refresh',
655→			});
656→		}
657→	}
658→
659→	private formatValidationErrors(errors: ValidationError[]): string {
660→		return errors
661→			.map(
662→				(error) =>
663→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
664→			)
665→			.join('; ');
666→	}
667→}
