217→	private parseJsonField<T>(field: T | string | null): T | null {
218→		if (field === null || field === undefined) {
219→			return null;
220→		}
221→		if (typeof field === 'string') {
222→			try {
223→				return JSON.parse(field) as T;
224→			} catch {
225→				return null;
226→			}
227→		}
228→		return field;
229→	}
230→
231→	private sanitizeBrandNames(brands: string[]): string[] {
232→		const brandNamePattern = /^[a-zA-Z0-9\s_\-+.'&®™\/]+$/;
233→		return brands.filter((brand) => {
234→			if (typeof brand !== 'string' || brand.length === 0 || brand.length > 40) {
235→				return false;
236→			}
237→			return brandNamePattern.test(brand);
238→		});
239→	}
